import React, { useState, useEffect } from 'react';
import { useAuth } from '../../contexts/AuthContext';
import { 
  BarChart3, 
  TrendingUp, 
  PieChart, 
  Calendar, 
  Filter,
  Download,
  Activity,
  CheckCircle,
  Clock,
  AlertCircle
} from 'lucide-react';

const Analytics = () => {
  const { api } = useAuth();
  const [stats, setStats] = useState({
    total: 0,
    resolved: 0,
    pending: 0,
    inProgress: 0,
    byCategory: {},
    byPriority: {}
  });
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchAnalytics();
  }, []);

  const fetchAnalytics = async () => {
    try {
      setLoading(true);
      const response = await api.get('/complaints/stats');
      setStats(response.data);
    } catch (error) {
      console.error('Error fetching analytics:', error);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary-600"></div>
      </div>
    );
  }

  return (
    <div className="p-6 space-y-6">
      {/* Header Section */}
      <div className="bg-gradient-to-r from-primary-600 to-primary-700 rounded-xl p-8 text-white flex flex-col sm:flex-row sm:items-center justify-between gap-6 overflow-hidden relative shadow-lg">
        <div className="relative z-10">
          <h1 className="text-3xl font-bold mb-2 flex items-center">
            <BarChart3 className="mr-3 h-8 w-8" />
            System Analytics
          </h1>
          <p className="text-primary-100 italic">Gain insights into system performance and complaint trends</p>
        </div>
        <button className="relative z-10 bg-white text-primary-600 px-6 py-3 rounded-lg font-bold hover:bg-primary-50 transition-all shadow-md flex items-center space-x-2 border-b-4 border-primary-100 active:border-b-0 active:translate-y-1">
          <Download className="h-5 w-5" />
          <span>Export Report</span>
        </button>
        <div className="absolute top-0 right-0 -mr-16 -mt-16 h-64 w-64 rounded-full bg-white/10 blur-3xl"></div>
      </div>

      {/* Main Stats Summary */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard 
          title="Total Reports" 
          value={stats.totalComplaints || 0} 
          icon={<Activity className="h-6 w-6 text-primary-600" />} 
          color="bg-primary-50"
        />
        <StatCard 
          title="Resolved" 
          value={stats.resolvedComplaints || 0} 
          icon={<CheckCircle className="h-6 w-6 text-success-600" />} 
          color="bg-success-50"
          subtitle={`${((stats.resolvedComplaints / stats.totalComplaints) * 100 || 0).toFixed(1)}% resolution rate`}
        />
        <StatCard 
          title="In Progress" 
          value={stats.inProgressComplaints || 0} 
          icon={<TrendingUp className="h-6 w-6 text-blue-600" />} 
          color="bg-blue-50"
        />
        <StatCard 
          title="Pending Items" 
          value={stats.pendingComplaints || 0} 
          icon={<Clock className="h-6 w-6 text-warning-600" />} 
          color="bg-warning-50"
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Mock Chart Area - Category Distribution */}
        <div className="card">
          <div className="flex items-center justify-between mb-6">
            <h2 className="text-lg font-bold text-gray-900 flex items-center">
              <PieChart className="mr-2 h-5 w-5 text-primary-600" />
              Category Distribution
            </h2>
            <button className="text-sm font-medium text-primary-600 hover:text-primary-700">View Details</button>
          </div>
          <div className="space-y-4">
            {/* Visual representation of categories */}
            {['ELECTRICAL', 'PLUMBING', 'CLEANING', 'IT_INFRASTRUCTURE', 'OTHER'].map((cat, idx) => (
              <div key={cat} className="space-y-1">
                <div className="flex justify-between text-xs font-bold text-gray-500 uppercase">
                  <span>{cat.replace('_', ' ')}</span>
                  <span>{Math.floor(Math.random() * 40) + 10}%</span>
                </div>
                <div className="h-2 w-full bg-gray-100 rounded-full overflow-hidden">
                  <div 
                    className={`h-full bg-primary-${500 - (idx * 100)} rounded-full`} 
                    style={{ width: `${Math.floor(Math.random() * 60) + 20}%` }}
                  ></div>
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* Priority Trends */}
        <div className="card">
           <div className="flex items-center justify-between mb-6">
            <h2 className="text-lg font-bold text-gray-900 flex items-center">
              <TrendingUp className="mr-2 h-5 w-5 text-primary-600" />
              Priority Analysis
            </h2>
            <div className="flex items-center space-x-2 text-xs bg-gray-50 p-1 rounded-lg">
                <span className="px-2 py-1 bg-white rounded shadow-sm font-bold text-primary-600">Last 30 Days</span>
                <span className="px-2 py-1 text-gray-500">Yearly</span>
            </div>
          </div>
          <div className="flex items-end justify-between h-48 pt-4 gap-2">
            {[45, 60, 30, 80, 50, 90, 65].map((val, i) => (
                <div key={i} className="flex-1 group relative">
                    <div className="absolute -top-6 left-1/2 -translate-x-1/2 opacity-0 group-hover:opacity-100 transition-opacity bg-gray-900 text-white text-[10px] py-1 px-2 rounded whitespace-nowrap z-20">
                        {val} complaints
                    </div>
                    <div 
                        className="w-full bg-primary-100 hover:bg-primary-500 rounded-t-lg transition-all duration-300 relative overflow-hidden" 
                        style={{ height: `${val}%` }}
                    >
                        <div className="absolute top-0 left-0 w-full h-1 bg-white/20"></div>
                    </div>
                    <div className="text-[10px] font-bold text-gray-400 mt-2 text-center">Day {i+1}</div>
                </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

const StatCard = ({ title, value, icon, color, subtitle }) => (
  <div className="bg-white rounded-2xl p-6 border border-gray-100 shadow-sm hover:shadow-md transition-shadow">
    <div className="flex items-center justify-between mb-4">
      <div className={`p-3 rounded-xl ${color}`}>
        {icon}
      </div>
      <div className="text-[10px] font-extrabold text-success-600 bg-success-50 px-2 py-1 rounded-full">+12%</div>
    </div>
    <div>
      <h3 className="text-sm font-bold text-gray-500 uppercase tracking-wider">{title}</h3>
      <div className="flex items-baseline space-x-2">
        <span className="text-3xl font-black text-gray-900">{value}</span>
        {subtitle && <span className="text-xs text-gray-400 font-medium">{subtitle}</span>}
      </div>
    </div>
  </div>
);

export default Analytics;
